SELECT c.description
FROM course c
WHERE c.course_code = #{courseId}

SELECT s.student_id
FROM student s
WHERE s.user_id = #{userId}

SELECT request_id
FROM course_request
WHERE student_id = #{studentId}
  AND section_id = #{sectionId}
ORDER BY requested_at DESC
FETCH FIRST 1 ROW ONLY
